export default function hoverConfig(e) {

    let idElement = e.target.id
    let initialTime
    let finalTime

    if(e.type === 'mouseenter'){
        
        initialTime = new Date();
            
    }else if(e.type === 'mouseleave'){
            
        finalTime = `${date.getHours()}:${date.getMinutes()}:${date.getSeconds()}`
        console.log(finalTime - initialTime);

    }


}
